from aya_dash.settings import KeycloakSettings


def _build_validator(client_id: str | None = None, roles: list[str] | None = None, groups: list[str] | None = None):
    """Combines roles and groups validators with OR logic. Internal use only."""
    validators = []
    if roles:
        s = KeycloakSettings()
        validators.append(validator_for_keycloak_client_role_in(client_id=client_id or s.client_id, roles=roles))
    if groups:
        validators.append(validator_for_keycloak_group_in(groups))
    if not validators:
        raise ValueError("At least one of roles or groups must be provided")
    return lambda token: any(v(token) for v in validators)


def validator_for_keycloak_realm_role_in(roles: list[str]):
    """Check token has any of the given Keycloak realm roles (realm_access.roles)."""
    rp = set(roles)

    def validate(token: dict) -> bool:
        """Keycloak Realm Role Requirement"""
        return bool(rp & set(token.get("realm_access", {}).get("roles", [])))

    return validate


def validator_for_keycloak_client_role_in(client_id: str, roles: list[str]):
    """Check token has any of the given Keycloak client roles (resource_access.<client_id>.roles)."""
    rp = set(roles)

    def validate(token: dict) -> bool:
        """Keycloak Client Role Requirement"""
        return bool(rp & set(token.get("resource_access", {}).get(client_id, {}).get("roles", [])))

    return validate


def validator_for_keycloak_group_in(groups: list[str]):
    """Check token has any of the given Keycloak groups (groups claim)."""
    gp = set(groups)

    def validate(token: dict) -> bool:
        """Keycloak Group Requirement"""
        return bool(gp & set(token.get("groups", [])))

    return validate

