import urllib.request
from json import loads
from typing import Callable

from authlib.integrations.base_client import OAuthError
from authlib.integrations.flask_client import OAuth
from authlib.jose import JsonWebToken
from authlib.jose.errors import JoseError
from dash import Dash
from flask import abort, redirect, request, session, url_for
from loguru import logger
from werkzeug.middleware.proxy_fix import ProxyFix

from aya_dash.settings import KeycloakSettings

SKIP_PREFIXES = ("/login", "/authorized", "/logout", "/assets", "/_favicon")


def decode_jwt(token: str, jwks_uri: str, issuer: str) -> dict:
    """Verify JWT signature and claims using JWKS. Returns claims dict or {}."""
    if not token or token.count(".") < 2:
        return {}
    try:
        with urllib.request.urlopen(jwks_uri) as response:
            jwks = loads(response.read())
        claims_options = {"iss": {"essential": True, "value": issuer}}
        claims = JsonWebToken(["RS256"]).decode(token, jwks, claims_options=claims_options)
        claims.validate(leeway=60)
        return dict(claims)
    except JoseError as e:
        logger.warning(f"JWT verification failed: {e}")
        return {}
    except Exception as e:
        logger.exception(f"decode_jwt unexpected error: {e}")
        return {}


def get_user_name() -> str:
    try:
        claims = session["claims"]
        return claims.get("name") or claims.get("preferred_username", "No Username")
    except KeyError:
        return "Not Logged In"


def configure_authentication(
    app: Dash,
    settings: KeycloakSettings | None = None,
    home_page: str = "/",
    authorization_validators: list[Callable[[dict], bool]] | None = None,
) -> None:
    settings = settings or KeycloakSettings()
    flask_app = app.server
    flask_app.secret_key = settings.client_secret.get_secret_value()
    flask_app.config["PREFERRED_URL_SCHEME"] = "https"
    flask_app.wsgi_app = ProxyFix(flask_app.wsgi_app, x_for=1, x_proto=1, x_host=1, x_port=1)
    flask_app.config.update(SESSION_COOKIE_SECURE=True, SESSION_COOKIE_HTTPONLY=True)

    oauth = OAuth(flask_app)
    oauth.register(
        name="idp",
        client_id=settings.client_id,
        client_secret=settings.client_secret.get_secret_value(),
        server_metadata_url=settings.metadata_url,
        client_kwargs={"scope": settings.scope},
    )

    @flask_app.before_request
    def check_auth():
        if any(request.path.startswith(p) for p in SKIP_PREFIXES):
            return None
        if "claims" not in session:
            if request.path.startswith("/_dash"):
                abort(401)
            return redirect(url_for("oidc_login"))
        return None

    @flask_app.route("/login")
    def oidc_login():
        return oauth.idp.authorize_redirect(url_for("oidc_authorize", _external=True))

    @flask_app.route("/authorized")
    def oidc_authorize():
        try:
