from functools import wraps

from dash import html
from dash.exceptions import PreventUpdate
from flask import abort, has_request_context, session

from aya_dash.settings import KeycloakSettings
from aya_dash.validators import _build_validator


def require_role(
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Protect a Flask route. Aborts 403 (or calls on_denied) if token lacks required role/group.

    ```python
    @app.server.route("/admin")
    @require_role(roles=["admin"])
    def admin(): ...
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                return on_denied() if on_denied is not None else abort(403)
            return f(*args, **kwargs)

        return decorated

    return decorator


def require_group(
    groups: list[str],
    on_denied=None,
):
    """Protect a Flask route. Aborts 403 (or calls on_denied) if user is not in any of the given groups.

    ```python
    @app.server.route("/team")
    @require_group(groups=["/data-team"])
    def team(): ...
    ```
    """
    validator = _build_validator(None, None, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                return on_denied() if on_denied is not None else abort(403)
            return f(*args, **kwargs)

        return decorated

    return decorator


def protect_layout(
    layout,
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Wrap a static Dash layout for role/group protection. Use with dash.register_page.

    ```python
    layout = protect_layout(html.Div("Admin only"), roles=["admin"])
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def _layout():
        if not has_request_context():
            return layout
        if not validator(session.get("claims", {})):
            return on_denied() if on_denied else html.P("Access denied.")
        return layout

    return _layout


def protect_component(
    component,
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Conditionally render a component inside a function layout.

    ```python
    def layout():
        return html.Div(
            [
                protect_component(html.Div("Admins only"), roles=["admin"]),
            ]
        )
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)
    if not validator(session.get("claims", {})):
        return on_denied() if on_denied else None
    return component


def protect_callback(roles=None, groups=None, client_id=None, on_denied=None):
    """Protect a Dash callback. Raises PreventUpdate (or calls on_denied) if unauthorized.

    ```python
    @callback(Output("out", "children"), Input("in", "value"))
    @protect_callback(roles=["editor"])
    def update(value): ...
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                if on_denied is not None:
                    return on_denied()
                raise PreventUpdate
            return f(*args, **kwargs)

        return decorated

    return decorator

from pydantic import AliasChoices, AnyHttpUrl, Field, SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict


class KeycloakSettings(BaseSettings):
    keycloak_url: AnyHttpUrl = Field(default="https://auth.ltplabs.com", validation_alias=AliasChoices("KEYCLOAK_URL"))
    realm: str = Field(validation_alias=AliasChoices("REALM"))
    client_id: str = Field(validation_alias=AliasChoices("OIDC_CLIENT_ID", "CLIENT_ID"))
    client_secret: SecretStr = Field(validation_alias=AliasChoices("OIDC_CLIENT_SECRET", "CLIENT_SECRET"))
    scope: str = Field(default="openid", validation_alias=AliasChoices("OIDC_SCOPE", "SCOPE"))

    @property
    def _base(self) -> str:
        return str(self.keycloak_url).rstrip("/")

    @property
    def metadata_url(self) -> str:
        return f"{self._base}/realms/{self.realm}/.well-known/openid-configuration"

    @property
    def jwks_uri(self) -> str:
        return f"{self._base}/realms/{self.realm}/protocol/openid-connect/certs"

    @property
    def issuer(self) -> str:
        return f"{self._base}/realms/{self.realm}"

    @property
    def end_session_fallback(self) -> str:
        return f"{self._base}/realms/{self.realm}/protocol/openid-connect/logout"

    model_config = SettingsConfigDict(extra="ignore")

