from functools import wraps

from dash import html
from dash.exceptions import PreventUpdate
from flask import abort, has_request_context, session

from aya_dash.settings import KeycloakSettings
from aya_dash.validators import _build_validator


def require_role(
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Protect a Flask route. Aborts 403 (or calls on_denied) if token lacks required role/group.

    ```python
    @app.server.route("/admin")
    @require_role(roles=["admin"])
    def admin(): ...
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                return on_denied() if on_denied is not None else abort(403)
            return f(*args, **kwargs)

        return decorated

    return decorator


def require_group(
    groups: list[str],
    on_denied=None,
):
    """Protect a Flask route. Aborts 403 (or calls on_denied) if user is not in any of the given groups.

    ```python
    @app.server.route("/team")
    @require_group(groups=["/data-team"])
    def team(): ...
    ```
    """
    validator = _build_validator(None, None, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                return on_denied() if on_denied is not None else abort(403)
            return f(*args, **kwargs)

        return decorated

    return decorator


def protect_layout(
    layout,
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Wrap a static Dash layout for role/group protection. Use with dash.register_page.

    ```python
    layout = protect_layout(html.Div("Admin only"), roles=["admin"])
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def _layout():
        if not has_request_context():
            return layout
        if not validator(session.get("claims", {})):
            return on_denied() if on_denied else html.P("Access denied.")
        return layout

    return _layout


def protect_component(
    component,
    roles: list[str] | None = None,
    groups: list[str] | None = None,
    client_id: str | None = None,
    on_denied=None,
):
    """Conditionally render a component inside a function layout.

    ```python
    def layout():
        return html.Div(
            [
                protect_component(html.Div("Admins only"), roles=["admin"]),
            ]
        )
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)
    if not validator(session.get("claims", {})):
        return on_denied() if on_denied else None
    return component


def protect_callback(roles=None, groups=None, client_id=None, on_denied=None):
    """Protect a Dash callback. Raises PreventUpdate (or calls on_denied) if unauthorized.

    ```python
    @callback(Output("out", "children"), Input("in", "value"))
    @protect_callback(roles=["editor"])
    def update(value): ...
    ```
    """
    s = KeycloakSettings()
    validator = _build_validator(client_id or s.client_id, roles, groups)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not validator(session.get("claims", {})):
                if on_denied is not None:
                    return on_denied()
                raise PreventUpdate
            return f(*args, **kwargs)

        return decorated

    return decorator

import pytest

from aya_dash.validators import (
    _build_validator,
    validator_for_keycloak_client_role_in,
    validator_for_keycloak_group_in,
    validator_for_keycloak_realm_role_in,
)


def test_realm_role_validator_passes_when_any_role_matches():
    validator = validator_for_keycloak_realm_role_in(["admin", "manager"])
    sample_token = {"realm_access": {"roles": ["user", "admin"]}}

    assert validator(sample_token)


def test_realm_role_validator_fails_when_no_role_matches():
    validator = validator_for_keycloak_realm_role_in(["admin"])
    sample_token = {"realm_access": {"roles": ["user"]}}

    assert not validator(sample_token)


def test_realm_role_validator_fails_when_claim_is_missing():
    validator = validator_for_keycloak_realm_role_in(["admin"])
    sample_token = {}

    assert not validator(sample_token)


def test_client_role_validator_checks_only_configured_client():
    validator = validator_for_keycloak_client_role_in("my-client", ["editor"])
    sample_token = {
        "resource_access": {
            "other-client": {"roles": ["editor"]},
            "my-client": {"roles": ["viewer"]},
        }
    }

    assert not validator(sample_token)


def test_client_role_validator_passes_when_client_role_matches():
    validator = validator_for_keycloak_client_role_in("my-client", ["editor"])
    sample_token = {"resource_access": {"my-client": {"roles": ["editor"]}}}

    assert validator(sample_token)


def test_group_validator_passes_when_any_group_matches():
    validator = validator_for_keycloak_group_in(["/finance", "/admin"])
    sample_token = {"groups": ["/users", "/finance"]}

    assert validator(sample_token)


def test_group_validator_fails_when_no_group_matches():
    validator = validator_for_keycloak_group_in(["/finance"])
    sample_token = {"groups": ["/users"]}

    assert not validator(sample_token)


def test_build_validator_uses_or_logic_for_roles_and_groups():
    validator = _build_validator(client_id="my-client", roles=["admin"], groups=["/finance"])
    sample_group_token = {"groups": ["/finance"]}
    sample_role_token = {"resource_access": {"my-client": {"roles": ["admin"]}}}

    assert validator(sample_group_token)
    assert validator(sample_role_token)


def test_build_validator_fails_when_neither_role_nor_group_matches():
    validator = _build_validator(client_id="my-client", roles=["admin"], groups=["/finance"])
    sample_token = {
        "groups": ["/users"],
        "resource_access": {"my-client": {"roles": ["viewer"]}},
    }

    assert not validator(sample_token)


def test_build_validator_requires_roles_or_groups():
    with pytest.raises(ValueError, match="At least one of roles or groups must be provided"):
        _build_validator(client_id="my-client", roles=None, groups=None)

