import pytest
from dash import Dash, html
from dash.exceptions import PreventUpdate
from flask import Flask, session

from aya_dash import decorators


class FakeSettings:
    client_id = "my-client"


@pytest.fixture(autouse=True)
def patch_keycloak_settings(monkeypatch):
    monkeypatch.setattr(decorators, "KeycloakSettings", FakeSettings)


@pytest.fixture
def flask_app():
    app = Flask(__name__)
    app.secret_key = "test-secret"
    return app


def test_require_role_allows_access_when_token_matches(flask_app):
    @flask_app.route("/admin")
    @decorators.require_role(roles=["admin"], client_id="my-client")
    def admin():
        return "ok"

    client = flask_app.test_client()
    with client.session_transaction() as flask_session:
        flask_session["claims"] = {"resource_access": {"my-client": {"roles": ["admin"]}}}

    response = client.get("/admin")

    assert response.status_code == 200
    assert response.data == b"ok"


def test_require_role_returns_403_when_unauthorized(flask_app):
    @flask_app.route("/admin")
    @decorators.require_role(roles=["admin"], client_id="my-client")
    def admin():
        return "ok"

    client = flask_app.test_client()
    response = client.get("/admin")

    assert response.status_code == 403


def test_require_role_uses_on_denied_when_provided(flask_app):
    @flask_app.route("/admin")
    @decorators.require_role(roles=["admin"], client_id="my-client", on_denied=lambda: ("nope", 418))
    def admin():
        return "ok"

    client = flask_app.test_client()
    response = client.get("/admin")

    assert response.status_code == 418
    assert response.data == b"nope"


def test_require_group_allows_access_when_group_matches(flask_app):
    @flask_app.route("/team")
    @decorators.require_group(groups=["/finance"])
    def team():
        return "ok"

    client = flask_app.test_client()
    with client.session_transaction() as flask_session:
        flask_session["claims"] = {"groups": ["/finance"]}

    response = client.get("/team")

