    assert response.data == b"ok"


def test_require_group_uses_on_denied_when_provided(flask_app):
    @flask_app.route("/team")
    @decorators.require_group(groups=["/finance"], on_denied=lambda: ("nope", 403))
    def team():
        return "ok"

    client = flask_app.test_client()
    response = client.get("/team")

    assert response.status_code == 403
    assert response.data == b"nope"


def test_protect_layout_returns_original_layout_without_request_context():
    layout = html.Div("Admin only")
    protected = decorators.protect_layout(layout, roles=["admin"], client_id="my-client")

    assert protected() is layout


def test_protect_layout_allows_authorized_request(flask_app):
    layout = html.Div("Admin only")
    protected = decorators.protect_layout(layout, roles=["admin"], client_id="my-client")

    with flask_app.test_request_context("/"):
        session["claims"] = {"resource_access": {"my-client": {"roles": ["admin"]}}}

        assert protected() is layout


def test_protect_layout_returns_denied_component_when_unauthorized(flask_app):
    layout = html.Div("Admin only")
    protected = decorators.protect_layout(layout, roles=["admin"], client_id="my-client")

    with flask_app.test_request_context("/"):
        result = protected()

    assert result.children == "Access denied."


def test_protect_layout_uses_custom_on_denied(flask_app):
    layout = html.Div("Admin only")
    denied = html.Div("nope")
    protected = decorators.protect_layout(
        layout,
        roles=["admin"],
        client_id="my-client",
        on_denied=lambda: denied,
    )

    with flask_app.test_request_context("/"):
        result = protected()

    assert result is denied


