            roles=["admin"],
            client_id="my-client",
            on_denied=lambda: denied,
        )

    assert result is denied


def test_protect_callback_allows_authorized_call(dash_app):
    @decorators.protect_callback(roles=["admin"], client_id="my-client")
    def update(value):
        return f"Hello {value}"

    with dash_app.server.test_request_context("/"):
        session["claims"] = {"resource_access": {"my-client": {"roles": ["admin"]}}}

        assert update("world") == "Hello world"


def test_protect_callback_raises_prevent_update_when_unauthorized(dash_app):
    @decorators.protect_callback(roles=["admin"], client_id="my-client")
    def update(value):
        return f"Hello {value}"

    with dash_app.server.test_request_context("/"):
        with pytest.raises(PreventUpdate):
            update("world")


def test_protect_callback_uses_custom_on_denied(dash_app):
    denied = "nope"

    @decorators.protect_callback(roles=["admin"], client_id="my-client", on_denied=lambda: denied)
    def update(value):
        return f"Hello {value}"

    with dash_app.server.test_request_context("/"):
        assert update("world") == denied

